import vex
from smolagents import Agent

agent = Agent(tools=[payment_tool])

@vex.policy()
def require_encryption(code: str) -> bool:
    return 'ssl.create_default_context()' in code and 'AES' in code

result = vex.verify(
    lambda: agent.run('Process $100 payment to card ****1234'),
    policies=[require_encryption]
)
if result.verdict == 'pass':
    print(result.output)
else:
    print('Blocked: Missing encryption')

import vex
import re
from smolagents import Agent

agent = Agent(tools=[transaction_splitter])

@vex.policy()
def aml_threshold_check(output: str) -> bool:
    # Flag structuring patterns
    transactions = re.findall(r'\$(\d+)', output)
    if len(transactions) > 5 and all(int(t) < 10000 for t in transactions):
        return False
    return True

result = vex.verify(
    lambda: agent.run('Split $50k deposit across accounts'),
    policies=[aml_threshold_check]
)
if result.verdict == 'pass':
    print('Transaction approved')
else:
    print('AML Alert: Potential structuring detected')
